import React, { useState,useEffect,useRef } from 'react'
import {Container,ListGroup} from 'react-bootstrap'
import './MyStyle.css';
import {Nav,FormControl} from 'react-bootstrap'
const Songlist=({songs,Setcurrentsongindex,playing,Setplaying})=>{

const [posts,Setposts]=useState(null)
const [people,Setpeople]=useState(50)

function change(e){
    Setcurrentsongindex(e)
    Setplaying(true)
}
/*
useEffect(()=>{
axios
    .get(`https://jsonplaceholder.typicode.com/posts/${id}`)
    .then(res=>{
        Setposts(res.data)
    })
},[id])
*/

    return(

        <div className="songlistbox">
             <center><h1 className="text-4xl">Songsss</h1></center>
        <center>
             <div className="song-list-box rounded-md bg-purple-600 rounded-xl ring-4 ring-indigo-900 shadow-2xl">
            <div className="searchbox p-2">
            <FormControl
      placeholder="Search Song"
      aria-label="Username"
      aria-describedby="basic-addon1"
    />
            </div>
                 
            <ListGroup className=" listing py-4 px-2  space-y-1 " as="ol">
                {
                    songs.map(item=>(
                        <button className="rounded-xl" key={item.id}   onClick={()=>change(item.id)}><ListGroup.Item  key={item.id}  as="li" >
                        <strong>{item.title}</strong>
                        <div className="align-item-start">{item.artist}</div>
                    </ListGroup.Item>
                    </button>
                    ))
                }
            

    </ListGroup>
    
            </div>
            </center>

        </div>
    )
}

export default Songlist;
